export const ClosureReasonCodes = {
  RUNTIME_NOT_READY: 'RUNTIME_NOT_READY',
  GOVERNANCE_NOT_READY: 'GOVERNANCE_NOT_READY',
  PAYMENT_WITHOUT_AUTHORITY: 'PAYMENT_WITHOUT_AUTHORITY',
  CUSTODY_INVALID: 'CUSTODY_INVALID',
  OWNERSHIP_INVALID: 'OWNERSHIP_INVALID',
  ENTITLEMENT_FALSE: 'ENTITLEMENT_FALSE',
  RELEASE_PREMATURE: 'RELEASE_PREMATURE',
  BYPASS_ATTEMPT_DETECTED: 'BYPASS_ATTEMPT_DETECTED',
  ATTESTATION_REQUIRED: 'ATTESTATION_REQUIRED'
} as const

export type ClosureReasonCode =
  typeof ClosureReasonCodes[keyof typeof ClosureReasonCodes]
